package com.example.samlsp.service;

import com.example.samlsp.config.SamlSpProperties;
import org.opensaml.security.credential.Credential;
import org.opensaml.security.credential.BasicCredential;
import org.opensaml.security.x509.BasicX509Credential;
import org.springframework.stereotype.Service;

import javax.annotation.PostConstruct;
import java.io.FileInputStream;
import java.io.InputStream;
import java.security.KeyFactory;
import java.security.PrivateKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.security.spec.PKCS8EncodedKeySpec;
import java.util.Base64;
import java.nio.file.Files;
import java.nio.file.Paths;

@Service
public class CredentialService {

    private final SamlSpProperties samlSpProperties;
    private BasicX509Credential spCredential;
    private BasicX509Credential idpCredential;

    public CredentialService(SamlSpProperties samlSpProperties) {
        this.samlSpProperties = samlSpProperties;
    }

    @PostConstruct
    public void init() throws Exception {
        this.spCredential = loadSpCredential();
        this.idpCredential = loadIdpCredential();
    }

    private BasicX509Credential loadSpCredential() throws Exception {
        X509Certificate cert = loadCertificate(samlSpProperties.getSpCertificatePath());
        PrivateKey privateKey = loadPrivateKey(samlSpProperties.getSpPrivateKeyPath());

        BasicX509Credential credential = new BasicX509Credential(cert, privateKey);
        credential.setEntityId(samlSpProperties.getEntityId());
        return credential;
    }

    private BasicX509Credential loadIdpCredential() throws Exception {
        X509Certificate cert = loadCertificate(samlSpProperties.getIdpCertificatePath());
        BasicX509Credential credential = new BasicX509Credential(cert);
        credential.setEntityId(samlSpProperties.getIdpEntityId());
        return credential;
    }

    private X509Certificate loadCertificate(String path) throws Exception {
        try (InputStream is = new FileInputStream(path)) {
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            return (X509Certificate) cf.generateCertificate(is);
        }
    }

    private PrivateKey loadPrivateKey(String path) throws Exception {
        String keyContent = new String(Files.readAllBytes(Paths.get(path)));
        keyContent = keyContent
                .replace("-----BEGIN PRIVATE KEY-----", "")
                .replace("-----END PRIVATE KEY-----", "")
                .replaceAll("\\s", "");

        byte[] keyBytes = Base64.getDecoder().decode(keyContent);
        PKCS8EncodedKeySpec spec = new PKCS8EncodedKeySpec(keyBytes);
        KeyFactory kf = KeyFactory.getInstance("RSA");
        return kf.generatePrivate(spec);
    }

    public BasicX509Credential getSpCredential() {
        return spCredential;
    }

    public BasicX509Credential getIdpCredential() {
        return idpCredential;
    }
}

