package com.example.samlsp.service;

import com.example.samlsp.config.SamlSpProperties;
import net.shibboleth.utilities.java.support.security.RandomIdentifierGenerationStrategy;
import org.joda.time.DateTime;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Marshaller;
import org.opensaml.core.xml.io.MarshallingException;
import org.opensaml.saml.common.xml.SAMLConstants;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.saml.saml2.core.impl.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.impl.SignatureBuilder;
import org.opensaml.xmlsec.signature.support.SignatureConstants;
import org.opensaml.xmlsec.signature.support.Signer;
import org.springframework.stereotype.Service;
import org.w3c.dom.Element;

import javax.xml.transform.TransformerFactory;
import javax.xml.transform.dom.DOMSource;
import javax.xml.transform.stream.StreamResult;
import java.io.StringWriter;
import java.util.Base64;

@Service
public class SamlRequestBuilder {

    private final SamlSpProperties samlSpProperties;
    private final CredentialService credentialService;
    private final RandomIdentifierGenerationStrategy idGenerator;

    public SamlRequestBuilder(SamlSpProperties samlSpProperties, CredentialService credentialService) {
        this.samlSpProperties = samlSpProperties;
        this.credentialService = credentialService;
        this.idGenerator = new RandomIdentifierGenerationStrategy();
    }

    public AuthnRequest buildAuthnRequest(String relayState) throws Exception {
        AuthnRequest authnRequest = new AuthnRequestBuilder().buildObject();

        authnRequest.setID(idGenerator.generateIdentifier());
        authnRequest.setIssueInstant(new DateTime());
        authnRequest.setDestination(samlSpProperties.getIdpSsoUrl());
        authnRequest.setProtocolBinding(SAMLConstants.SAML2_POST_BINDING_URI);
        authnRequest.setAssertionConsumerServiceURL(samlSpProperties.getAcsUrl());
        authnRequest.setForceAuthn(false);
        authnRequest.setIsPassive(false);

        // Set Issuer
        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(samlSpProperties.getEntityId());
        authnRequest.setIssuer(issuer);

        // Set NameIDPolicy
        NameIDPolicy nameIDPolicy = new NameIDPolicyBuilder().buildObject();
        nameIDPolicy.setFormat(NameIDType.EMAIL);
        nameIDPolicy.setAllowCreate(true);
        authnRequest.setNameIDPolicy(nameIDPolicy);

        // Set RequestedAuthnContext
        RequestedAuthnContext requestedAuthnContext = new RequestedAuthnContextBuilder().buildObject();
        requestedAuthnContext.setComparison(AuthnContextComparisonTypeEnumeration.MINIMUM);

        AuthnContextClassRef authnContextClassRef = new AuthnContextClassRefBuilder().buildObject();
        authnContextClassRef.setAuthnContextClassRef(AuthnContext.PASSWORD_AUTHN_CTX);
        requestedAuthnContext.getAuthnContextClassRefs().add(authnContextClassRef);
        authnRequest.setRequestedAuthnContext(requestedAuthnContext);

        // Sign the request if configured
        if (samlSpProperties.isAuthnRequestsSigned()) {
            signRequest(authnRequest);
        }

        return authnRequest;
    }

    private void signRequest(AuthnRequest authnRequest) throws Exception {
        Signature signature = new SignatureBuilder().buildObject();
        signature.setSigningCredential(credentialService.getSpCredential());
        signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
        signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);

        authnRequest.setSignature(signature);

        Marshaller marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory()
                .getMarshaller(authnRequest);
        marshaller.marshall(authnRequest);

        Signer.signObject(signature);
    }

    public String encodeAuthnRequest(AuthnRequest authnRequest) throws Exception {
        Marshaller marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory()
                .getMarshaller(authnRequest);
        Element element = marshaller.marshall(authnRequest);

        StringWriter writer = new StringWriter();
        TransformerFactory transformerFactory = TransformerFactory.newInstance();
        // Prevent XXE
        transformerFactory.setFeature("http://javax.xml.XMLConstants/feature/secure-processing", true);
        transformerFactory.newTransformer().transform(new DOMSource(element), new StreamResult(writer));

        return Base64.getEncoder().encodeToString(writer.toString().getBytes("UTF-8"));
    }

    public LogoutRequest buildLogoutRequest(String nameId, String sessionIndex) throws Exception {
        LogoutRequest logoutRequest = new LogoutRequestBuilder().buildObject();

        logoutRequest.setID(idGenerator.generateIdentifier());
        logoutRequest.setIssueInstant(new DateTime());
        logoutRequest.setDestination(samlSpProperties.getSloUrl());

        Issuer issuer = new IssuerBuilder().buildObject();
        issuer.setValue(samlSpProperties.getEntityId());
        logoutRequest.setIssuer(issuer);

        NameID nameID = new NameIDBuilder().buildObject();
        nameID.setFormat(NameIDType.EMAIL);
        nameID.setValue(nameId);
        logoutRequest.setNameID(nameID);

        if (sessionIndex != null) {
            SessionIndex sessionIdx = new SessionIndexBuilder().buildObject();
            sessionIdx.setSessionIndex(sessionIndex);
            logoutRequest.getSessionIndexes().add(sessionIdx);
        }

        if (samlSpProperties.isAuthnRequestsSigned()) {
            Signature signature = new SignatureBuilder().buildObject();
            signature.setSigningCredential(credentialService.getSpCredential());
            signature.setSignatureAlgorithm(SignatureConstants.ALGO_ID_SIGNATURE_RSA_SHA256);
            signature.setCanonicalizationAlgorithm(SignatureConstants.ALGO_ID_C14N_EXCL_OMIT_COMMENTS);
            logoutRequest.setSignature(signature);

            Marshaller marshaller = XMLObjectProviderRegistrySupport.getMarshallerFactory()
                    .getMarshaller(logoutRequest);
            marshaller.marshall(logoutRequest);
            Signer.signObject(signature);
        }

        return logoutRequest;
    }
}

