package com.example.samlsp.service;

import com.example.samlsp.config.SamlSpProperties;
import com.example.samlsp.exception.SamlValidationException;
import com.example.samlsp.model.SamlAuthenticatedUser;
import org.joda.time.DateTime;
import org.opensaml.core.xml.config.XMLObjectProviderRegistrySupport;
import org.opensaml.core.xml.io.Unmarshaller;
import org.opensaml.core.xml.io.UnmarshallerFactory;
import org.opensaml.saml.saml2.core.*;
import org.opensaml.security.credential.Credential;
import org.opensaml.xmlsec.signature.Signature;
import org.opensaml.xmlsec.signature.support.SignatureValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;
import org.w3c.dom.Element;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.util.*;

@Service
public class SamlResponseValidator {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseValidator.class);

    private final SamlSpProperties samlSpProperties;
    private final CredentialService credentialService;
    private final SamlReplayProtectionService replayProtectionService;

    public SamlResponseValidator(SamlSpProperties samlSpProperties,
                                  CredentialService credentialService,
                                  SamlReplayProtectionService replayProtectionService) {
        this.samlSpProperties = samlSpProperties;
        this.credentialService = credentialService;
        this.replayProtectionService = replayProtectionService;
    }

    public SamlAuthenticatedUser validateResponse(String samlResponseBase64) throws SamlValidationException {
        try {
            byte[] decodedResponse = Base64.getDecoder().decode(samlResponseBase64);
            Response response = parseResponse(decodedResponse);

            // Validate response status
            validateStatus(response);

            // Check for replay attacks
            validateReplay(response);

            // Validate destination
            validateDestination(response);

            // Validate issuer
            validateIssuer(response);

            // Validate signature on response
            if (response.getSignature() != null) {
                validateSignature(response.getSignature());
            }

            // Process assertions
            List<Assertion> assertions = response.getAssertions();
            if (assertions == null || assertions.isEmpty()) {
                throw new SamlValidationException("No assertions found in SAML response");
            }

            Assertion assertion = assertions.get(0);

            // Validate assertion signature if required
            if (samlSpProperties.isWantAssertionsSigned()) {
                if (assertion.getSignature() == null) {
                    throw new SamlValidationException("Assertion is not signed but signing is required");
                }
                validateSignature(assertion.getSignature());
            }

            // Validate conditions
            validateConditions(assertion);

            // Validate subject confirmation
            validateSubjectConfirmation(assertion);

            // Validate authn statements
            validateAuthnStatements(assertion);

            // Extract user information
            return extractUser(assertion);

        } catch (SamlValidationException e) {
            throw e;
        } catch (Exception e) {
            logger.error("Error validating SAML response", e);
            throw new SamlValidationException("Failed to validate SAML response: " + e.getMessage(), e);
        }
    }

    private Response parseResponse(byte[] responseBytes) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Prevent XXE attacks
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        Document document = builder.parse(new ByteArrayInputStream(responseBytes));
        Element element = document.getDocumentElement();

        UnmarshallerFactory unmarshallerFactory = XMLObjectProviderRegistrySupport.getUnmarshallerFactory();
        Unmarshaller unmarshaller = unmarshallerFactory.getUnmarshaller(element);

        if (unmarshaller == null) {
            throw new SamlValidationException("Unable to find unmarshaller for SAML response");
        }

        return (Response) unmarshaller.unmarshall(element);
    }

    private void validateStatus(Response response) throws SamlValidationException {
        Status status = response.getStatus();
        if (status == null || status.getStatusCode() == null) {
            throw new SamlValidationException("SAML response has no status");
        }

        String statusCode = status.getStatusCode().getValue();
        if (!StatusCode.SUCCESS.equals(statusCode)) {
            String message = "SAML authentication failed with status: " + statusCode;
            if (status.getStatusMessage() != null) {
                message += " - " + status.getStatusMessage().getMessage();
            }
            throw new SamlValidationException(message);
        }
    }

    private void validateReplay(Response response) throws SamlValidationException {
        String responseId = response.getID();
        if (responseId == null || responseId.isEmpty()) {
            throw new SamlValidationException("SAML response has no ID");
        }

        if (!replayProtectionService.registerResponse(responseId)) {
            throw new SamlValidationException("Replay attack detected: response ID already processed");
        }
    }

    private void validateDestination(Response response) throws SamlValidationException {
        String destination = response.getDestination();
        if (destination != null && !destination.equals(samlSpProperties.getAcsUrl())) {
            throw new SamlValidationException("Invalid destination in SAML response: " + destination);
        }
    }

    private void validateIssuer(Response response) throws SamlValidationException {
        Issuer issuer = response.getIssuer();
        if (issuer == null || !samlSpProperties.getIdpEntityId().equals(issuer.getValue())) {
            throw new SamlValidationException("Invalid issuer in SAML response");
        }
    }

    private void validateSignature(Signature signature) throws SamlValidationException {
        try {
            Credential idpCredential = credentialService.getIdpCredential();
            SignatureValidator.validate(signature, idpCredential);
        } catch (Exception e) {
            throw new SamlValidationException("Signature validation failed: " + e.getMessage(), e);
        }
    }

    private void validateConditions(Assertion assertion) throws SamlValidationException {
        Conditions conditions = assertion.getConditions();
        if (conditions == null) {
            throw new SamlValidationException("Assertion has no conditions");
        }

        DateTime now = new DateTime();
        int skew = samlSpProperties.getResponseSkew();

        if (conditions.getNotBefore() != null) {
            DateTime notBefore = conditions.getNotBefore().minusSeconds(skew);
            if (now.isBefore(notBefore)) {
                throw new SamlValidationException("Assertion is not yet valid (NotBefore condition)");
            }
        }

        if (conditions.getNotOnOrAfter() != null) {
            DateTime notOnOrAfter = conditions.getNotOnOrAfter().plusSeconds(skew);
            if (now.isAfter(notOnOrAfter) || now.isEqual(notOnOrAfter)) {
                throw new SamlValidationException("Assertion has expired (NotOnOrAfter condition)");
            }
        }

        // Validate audience restriction
        for (AudienceRestriction audienceRestriction : conditions.getAudienceRestrictions()) {
            boolean validAudience = false;
            for (Audience audience : audienceRestriction.getAudiences()) {
                if (samlSpProperties.getEntityId().equals(audience.getAudienceURI())) {
                    validAudience = true;
                    break;
                }
            }
            if (!validAudience) {
                throw new SamlValidationException("SP entity ID not found in audience restriction");
            }
        }
    }

    private void validateSubjectConfirmation(Assertion assertion) throws SamlValidationException {
        Subject subject = assertion.getSubject();
        if (subject == null) {
            throw new SamlValidationException("Assertion has no subject");
        }

        boolean validConfirmation = false;
        for (SubjectConfirmation confirmation : subject.getSubjectConfirmations()) {
            if ("urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(confirmation.getMethod())) {
                SubjectConfirmationData data = confirmation.getSubjectConfirmationData();
                if (data != null) {
                    DateTime now = new DateTime();
                    int skew = samlSpProperties.getResponseSkew();

                    if (data.getNotOnOrAfter() != null) {
                        DateTime notOnOrAfter = data.getNotOnOrAfter().plusSeconds(skew);
                        if (now.isAfter(notOnOrAfter)) {
                            continue;
                        }
                    }

                    if (data.getRecipient() != null && !samlSpProperties.getAcsUrl().equals(data.getRecipient())) {
                        continue;
                    }

                    validConfirmation = true;
                    break;
                }
            }
        }

        if (!validConfirmation) {
            throw new SamlValidationException("No valid subject confirmation found");
        }
    }

    private void validateAuthnStatements(Assertion assertion) throws SamlValidationException {
        List<AuthnStatement> authnStatements = assertion.getAuthnStatements();
        if (authnStatements == null || authnStatements.isEmpty()) {
            throw new SamlValidationException("No authentication statements found");
        }

        AuthnStatement authnStatement = authnStatements.get(0);
        DateTime authnInstant = authnStatement.getAuthnInstant();
        if (authnInstant != null) {
            DateTime maxAge = new DateTime().minusSeconds(samlSpProperties.getMaxAuthenticationAge());
            if (authnInstant.isBefore(maxAge)) {
                throw new SamlValidationException("Authentication is too old");
            }
        }

        if (authnStatement.getSessionNotOnOrAfter() != null) {
            if (new DateTime().isAfter(authnStatement.getSessionNotOnOrAfter())) {
                throw new SamlValidationException("Session has expired");
            }
        }
    }

    private SamlAuthenticatedUser extractUser(Assertion assertion) throws SamlValidationException {
        Subject subject = assertion.getSubject();
        NameID nameID = subject.getNameID();

        if (nameID == null || nameID.getValue() == null || nameID.getValue().trim().isEmpty()) {
            throw new SamlValidationException("No NameID found in assertion");
        }

        String userId = nameID.getValue();
        String nameIdFormat = nameID.getFormat();

        Map<String, List<String>> attributes = new HashMap<>();

        for (AttributeStatement attributeStatement : assertion.getAttributeStatements()) {
            for (org.opensaml.saml.saml2.core.Attribute attribute : attributeStatement.getAttributes()) {
                String name = attribute.getName();
                List<String> values = new ArrayList<>();
                for (org.opensaml.core.xml.XMLObject value : attribute.getAttributeValues()) {
                    if (value.getDOM() != null) {
                        values.add(value.getDOM().getTextContent());
                    }
                }
                attributes.put(name, values);
            }
        }

        String sessionIndex = null;
        if (!assertion.getAuthnStatements().isEmpty()) {
            sessionIndex = assertion.getAuthnStatements().get(0).getSessionIndex();
        }

        return new SamlAuthenticatedUser(userId, nameIdFormat, attributes, sessionIndex);
    }
}

// ==================== Replay Protection Service ====================

package com.example.samlsp.service;

import org.springframework.stereotype.Service;

import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

@Service
public class SamlReplayProtectionService {

    private final ConcurrentHashMap<String, Long> processedResponses = new ConcurrentHashMap<>();
    private static final long EXPIRY_DURATION_MS = 3600000; // 1 hour

    public SamlReplayProtectionService() {
        ScheduledExecutorService scheduler = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread t = new Thread(r, "saml-replay-cleanup");
            t.setDaemon(true);
            return t;
        });
        scheduler.scheduleAtFixedRate(this::cleanup, 10, 10, TimeUnit.MINUTES);
    }

    public boolean registerResponse(String responseId) {
        Long existing = processedResponses.putIfAbsent(responseId, System.currentTimeMillis());
        return existing == null;
    }

    private void cleanup() {
        long now = System.currentTimeMillis();
        processedResponses.entrySet().removeIf(entry ->
                (now - entry.getValue()) > EXPIRY_DURATION_MS);
    }
}

// ==================== Authenticated User Model ====================

package com.example.samlsp.model;

import java.io.Serializable;
import java.util.Collections;
import java.util.List;
import java.util.Map;

public class SamlAuthenticatedUser implements Serializable {

    private static final long serialVersionUID = 1L;

    private final String userId;
    private final String nameIdFormat;
    private final Map<String, List<String>> attributes;
    private final String sessionIndex;

    public SamlAuthenticatedUser(String userId, String nameIdFormat,
                                  Map<String, List<String>> attributes, String sessionIndex) {
        this.userId = userId;
        this.nameIdFormat = nameIdFormat;
        this.attributes = Collections.unmodifiableMap(attributes);
        this.sessionIndex = sessionIndex;
    }

    public String getUserId() { return userId; }
    public String getNameIdFormat() { return nameIdFormat; }
    public Map<String, List<String>> getAttributes() { return attributes; }
    public String getSessionIndex() { return sessionIndex; }

    public String getFirstAttribute(String name) {
        List<String> values = attributes.get(name);
        return (values != null && !values.isEmpty()) ? values.get(0) : null;
    }

    public String getEmail() {
        String email = getFirstAttribute("email");
        if (email == null) email = getFirstAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress");
        if (email == null) email = getFirstAttribute("urn:oid:0.9.2342.19200300.100.1.3");
        return email;
    }

    public String getDisplayName() {
        String name = getFirstAttribute("displayName");
        if (name == null) name = getFirstAttribute("http://schemas.xmlsoap.org/ws/2005/05/identity/claims/name");
        return name;
    }
}

