import com.example.samlsp.security.SamlAuthenticationFilter;
import com.example.samlsp.security.SamlAuthenticationProvider;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.authentication.builders.AuthenticationManagerBuilder;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
import org.springframework.security.web.csrf.CookieCsrfTokenRepository;
import org.springframework.security.web.header.writers.ReferrerPolicyHeaderWriter;

@Configuration
@EnableWebSecurity
public class SecurityConfig extends WebSecurityConfigurerAdapter {

    private final SamlAuthenticationProvider samlAuthenticationProvider;
    private final SamlAuthenticationFilter samlAuthenticationFilter;

    public SecurityConfig(SamlAuthenticationProvider samlAuthenticationProvider,
                          SamlAuthenticationFilter samlAuthenticationFilter) {
        this.samlAuthenticationProvider = samlAuthenticationProvider;
        this.samlAuthenticationFilter = samlAuthenticationFilter;
    }

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .headers()
                .contentSecurityPolicy("default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'")
                .and()
                .referrerPolicy(ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN)
                .and()
                .frameOptions().deny()
                .xssProtection().block(true)
                .and()
                .contentTypeOptions()
                .and()
                .httpStrictTransportSecurity()
                    .includeSubDomains(true)
                    .maxAgeInSeconds(31536000)
            .and()
            .and()
            .csrf()
                .csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
                .ignoringAntMatchers("/saml/acs", "/saml/slo") // SAML POST endpoints
            .and()
            .sessionManagement()
                .sessionCreationPolicy(SessionCreationPolicy.IF_REQUIRED)
                .maximumSessions(1)
                .expiredUrl("/saml/login")
            .and()
            .and()
            .authorizeRequests()
                .antMatchers("/saml/login", "/saml/acs", "/saml/metadata", "/saml/slo", "/health").permitAll()
                .anyRequest().authenticated()
            .and()
            .addFilterBefore(samlAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
            .logout()
                .logoutUrl("/logout")
                .logoutSuccessUrl("/saml/login")
                .invalidateHttpSession(true)
                .deleteCookies("JSESSIONID");
    }

    @Override
    protected void configure(AuthenticationManagerBuilder auth) {
        auth.authenticationProvider(samlAuthenticationProvider);
    }
}

// ==================== SAML Authentication Token ====================

package com.example.samlsp.security;

import com.example.samlsp.model.SamlAuthenticatedUser;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;

import java.util.Collection;
import java.util.Collections;

public class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final String samlResponse;
    private final SamlAuthenticatedUser authenticatedUser;

    // Pre-authentication constructor
    public SamlAuthenticationToken(String samlResponse) {
        super(Collections.emptyList());
        this.samlResponse = samlResponse;
        this.authenticatedUser = null;
        setAuthenticated(false);
    }

    // Post-authentication constructor
    public SamlAuthenticationToken(SamlAuthenticatedUser authenticatedUser,
                                    Collection<? extends GrantedAuthority> authorities) {
        super(authorities);
        this.samlResponse = null;
        this.authenticatedUser = authenticatedUser;
        setAuthenticated(true);
    }

    @Override
    public Object getCredentials() {
        return samlResponse;
    }

    @Override
    public Object getPrincipal() {
        return authenticatedUser != null ? authenticatedUser : "anonymous";
    }

    public SamlAuthenticatedUser getAuthenticatedUser() {
        return authenticatedUser;
    }
}

// ==================== SAML Authentication Provider ====================

package com.example.samlsp.security;

import com.example.samlsp.exception.SamlValidationException;
import com.example.samlsp.model.SamlAuthenticatedUser;
import com.example.samlsp.service.SamlResponseValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.authentication.AuthenticationProvider;
import org.springframework.security.authentication.AuthenticationServiceException;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.AuthenticationException;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.stereotype.Component;

import java.util.Collections;
import java.util.List;

@Component
public class SamlAuthenticationProvider implements AuthenticationProvider {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationProvider.class);

    private final SamlResponseValidator samlResponseValidator;

    public SamlAuthenticationProvider(SamlResponseValidator samlResponseValidator) {
        this.samlResponseValidator = samlResponseValidator;
    }

    @Override
    public Authentication authenticate(Authentication authentication) throws AuthenticationException {
        SamlAuthenticationToken token = (SamlAuthenticationToken) authentication;
        String samlResponse = (String) token.getCredentials();

        try {
            SamlAuthenticatedUser user = samlResponseValidator.validateResponse(samlResponse);

            List<SimpleGrantedAuthority> authorities = Collections.singletonList(
                    new SimpleGrantedAuthority("ROLE_USER"));

            logger.info("Successfully authenticated SAML user: {}", user.getUserId());

            return new SamlAuthenticationToken(user, authorities);

        } catch (SamlValidationException e) {
            logger.warn("SAML authentication failed: {}", e.getMessage());
            throw new AuthenticationServiceException("SAML authentication failed", e);
        }
    }

    @Override
    public boolean supports(Class<?> authentication) {
        return SamlAuthenticationToken.class.isAssignableFrom(authentication);
    }
}

// ==================== SAML Authentication Filter ====================

package com.example.samlsp.security;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.AuthenticationException;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.security.web.authentication.AuthenticationSuccessHandler;
import org.springframework.security.web.authentication.AuthenticationFailureHandler;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

@Component
public class SamlAuthenticationFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationFilter.class);
    private static final String ACS_URL = "/saml/acs";

    private final SamlAuthenticationProvider authenticationProvider;

    public SamlAuthenticationFilter(SamlAuthenticationProvider authenticationProvider) {
        this.authenticationProvider = authenticationProvider;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response,
                                     FilterChain filterChain) throws ServletException, IOException {

        if (!ACS_URL.equals(request.getServletPath()) || !"POST".equalsIgnoreCase(request.getMethod())) {
            filterChain.doFilter(request, response);
            return;
        }

        String samlResponse = request.getParameter("SAMLResponse");
        if (samlResponse == null || samlResponse.trim().isEmpty()) {
            logger.warn("No SAMLResponse parameter found in ACS request");
            response.sendRedirect("/saml/login?error=missing_response");
            return;
        }

        try {
            SamlAuthenticationToken token = new SamlAuthenticationToken(samlResponse);
            Authentication authentication = authenticationProvider.authenticate(token);

            SecurityContextHolder.getContext().setAuthentication(authentication);

            // Create new session to prevent session fixation
            HttpSession oldSession = request.getSession(false);
            if (oldSession != null) {
                oldSession.invalidate();
            }
            HttpSession newSession = request.getSession(true);
            newSession.setMaxInactiveInterval(3600);

            // Store authentication in new session
            SecurityContextHolder.getContext().setAuthentication(authentication);

            String relayState = request.getParameter("RelayState");
            String redirectUrl = "/dashboard";
            if (relayState != null && relayState.startsWith("/") && !relayState.contains("://")) {
                // Only allow relative URLs to prevent open redirect
                redirectUrl = relayState;
            }

            response.sendRedirect(redirectUrl);

        } catch (AuthenticationException e) {
            logger.error("SAML authentication failed", e);
            SecurityContextHolder.clearContext();
            response.sendRedirect("/saml/login?error=authentication_failed");
        }
    }
}

// ==================== SAML Controller ====================

package com.example.samlsp.controller;

import com.example.samlsp.config.SamlSpProperties;
import com.example.samlsp.model.SamlAuthenticatedUser;
import com.example.samlsp.security.SamlAuthenticationToken;
import com.example.samlsp.service.CredentialService;
import com.example.samlsp.service.SamlRequestBuilder;
import org.opensaml.saml.saml2.core.AuthnRequest;
import org.opensaml.saml.saml2.core.LogoutRequest;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.ResponseBody;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;

@Controller
@RequestMapping("/saml")
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    private final SamlSpProperties samlSpProperties;
    private final SamlRequestBuilder samlRequestBuilder;
    private final CredentialService credentialService;

    public SamlController(SamlSpProperties samlSpProperties,
                          SamlRequestBuilder samlRequestBuilder,
                          CredentialService credentialService) {
        this.samlSpProperties = samlSpProperties;
        this.samlRequestBuilder = samlRequestBuilder;
        this.credentialService = credentialService;
    }

    @GetMapping("/login")
    public String login(@RequestParam(required = false) String relayState, Model model) {
        try {
            AuthnRequest authnRequest = samlRequestBuilder.buildAuthnRequest(relayState);
            String encodedRequest = samlRequestBuilder.encodeAuthnRequest(authnRequest);

            model.addAttribute("samlRequest", encodedRequest);
            model.addAttribute("idpSsoUrl", samlSpProperties.getIdpSsoUrl());
            model.addAttribute("relayState", relayState != null ? relayState : "/dashboard");

            return "saml-redirect";

        } catch (Exception e) {
            logger.error("Error building SAML AuthnRequest", e);
            model.addAttribute("error", "Failed to initiate SSO login");
            return "error";
        }
    }

    @GetMapping("/logout")
    public String logout(HttpServletRequest request, Model model) {
        try {
            Authentication auth = SecurityContextHolder.getContext().getAuthentication();

            if (auth instanceof SamlAuthenticationToken) {
                SamlAuthenticatedUser user = ((SamlAuthenticationToken) auth).getAuthenticatedUser();

                if (user != null && samlSpProperties.getSloUrl() != null) {
                    LogoutRequest logoutRequest = samlRequestBuilder.buildLogoutRequest(
                            user.getUserId(), user.getSessionIndex());
                    String encodedRequest = samlRequestBuilder.encodeAuthnRequest(null); // Simplified

                    // Invalidate local session
                    HttpSession session = request.getSession(false);
                    if (session != null) {
                        session.invalidate();
                    }
                    SecurityContextHolder.clearContext();

                    model.addAttribute("sloUrl", samlSpProperties.getSloUrl());
                    return "saml-logout-redirect";
                }
            }

            // Fallback: local logout only
            HttpSession session = request.getSession(false);
            if (session != null) {
                session.invalidate();
            }
            SecurityContextHolder.clearContext();

            return "redirect:/saml/login";

        } catch (Exception e) {
            logger.error("Error during SAML logout", e);
            SecurityContextHolder.clearContext();
            return "redirect:/saml/login";
        }
    }

    @GetMapping("/metadata")
    @ResponseBody
    public String metadata() {
        StringBuilder sb = new StringBuilder();
        sb.append("<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n");
        sb.append("<md:EntityDescriptor xmlns:md=\"urn:oasis:names:tc:SAML:2.0:metadata\" ");
        sb.append("entityID=\"").append(escapeXml(samlSpProperties.getEntityId())).append("\">\n");
        sb.append("  <md:SPSSODescriptor ");
        sb.append("AuthnRequestsSigned=\"").append(samlSpProperties.isAuthnRequestsSigned()).append("\" ");
        sb.append("WantAssertionsSigned=\"").append(samlSpProperties.isWantAssertionsSigned()).append("\" ");
        sb.append("protocolSupportEnumeration=\"urn:oasis:names:tc:SAML:2.0:protocol\">\n");

        // KeyDescriptor for signing
        try {
            java.security.cert.X509Certificate cert = credentialService.getSpCredential().getEntityCertificate();
            String certBase64 = java.util.Base64.getEncoder().encodeToString(cert.getEncoded());

            sb.append("    <md:KeyDescriptor use=\"signing\">\n");
            sb.append("      <ds:KeyInfo xmlns:ds=\"http://www.w3.org/2000/09/xmldsig#\">\n");
            sb.append("        <ds:X509Data>\n");
            sb.append("          <ds:X509Certificate>").append(certBase64).append("</ds:X509Certificate>\n");
            sb.append("        </ds:X509Data>\n");
            sb.append("      </ds:KeyInfo>\n");
            sb.append("    </md:KeyDescriptor>\n");

            sb.append("    <md:KeyDescriptor use=\"encryption\">\n");
            sb.append("      <ds:KeyInfo xmlns:ds=\"http://www.w3.org/2000/09/xmldsig#\">\n");
            sb.append("        <ds:X509Data>\n");
            sb.append("          <ds:X509Certificate>").append(certBase64).append("</ds:X509Certificate>\n");
            sb.append("        </ds:X509Data>\n");
            sb.append("      </ds:KeyInfo>\n");
            sb.append("    </md:KeyDescriptor>\n");
        } catch (Exception e) {
            logger.error("Error encoding certificate for metadata", e);
        }

        sb.append("    <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>\n");
        sb.append("    <md:AssertionConsumerService ");
        sb.append("Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" ");
        sb.append("Location=\"").append(escapeXml(samlSpProperties.getAcsUrl())).append("\" ");
        sb.append("index=\"0\" isDefault=\"true\"/>\n");

        if (samlSpProperties.getSloUrl() != null) {
            sb.append("    <md:SingleLogoutService ");
            sb.append("Binding=\"urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST\" ");
            sb.append("Location=\"").append(escapeXml(samlSpProperties.getSloUrl())).append("\"/>\n");
        }

        sb.append("  </md:SPSSODescriptor>\n");
        sb.append("</md:EntityDescriptor>");

        return sb.toString();
    }

    private String escapeXml(String input) {
        if (input == null) return "";
        return input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&apos;");
    }
}

// ==================== Dashboard Controller ====================

package com.example.samlsp.controller;

import com.example.samlsp.model.SamlAuthenticatedUser;
import com.example.samlsp.security.SamlAuthenticationToken;
import org.springframework.security.core.Authentication;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class DashboardController {

    @GetMapping("/dashboard")
    public String dashboard(Authentication authentication, Model model) {
        if (authentication instanceof SamlAuthenticationToken) {
            SamlAuthenticatedUser user = ((SamlAuthenticationToken) authentication).getAuthenticatedUser();
            model.addAttribute("userId", user.getUserId());
            model.addAttribute("email", user.getEmail());
            model.addAttribute("displayName", user.getDisplayName());
            model.addAttribute("attributes", user.getAttributes());
        }
        return "dashboard";
    }

    @GetMapping("/")
    public String home() {
        return "redirect:/dashboard";
    }
}

